#include <stdio.h>

int main() {
    int a = 5; int b = 10; int c = a + b;
    printf("Sum: %d\n", c); printf("Value of a: %d\n", a);
    if (c > 10) { printf("Greater than 10\n"); }
    int i = 0; i = i + 1; printf("i = %d\n", i);
    int x = 2; int y = 3; int z = x * y;
    printf("Multiplication: %d\n", z);
    return 0;
}
